// Parse la réponse Claude et prépare les 9 slides pour Templated.io
const raw = $input.first().json.content[0].text || '';

let c;
try {
  const clean = raw.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  c = JSON.parse(clean);
} catch(e) {
  throw new Error('Parse erreur: ' + e.message + ' | Début: ' + raw.substring(0, 300));
}

const sujet = $('Supabase — Get Sujet').first().json;

// IDs de templates Templated.io — remplacer par vos propres IDs
const TPL_COVER    = 'YOUR_COVER_TEMPLATE_ID';
const TPL_STANDARD = 'YOUR_STANDARD_TEMPLATE_ID';
const TPL_CTA      = 'YOUR_CTA_TEMPLATE_ID';

// Wrapper pour format Templated.io : { layerName: { text: "valeur" } }
function wrapForTempled(obj) {
  const wrapped = {};
  for (const [key, value] of Object.entries(obj)) {
    wrapped[key] = { text: String(value) };
  }
  return wrapped;
}

const slides = [
  {
    slide: 1,
    template_id: TPL_COVER,
    layers: wrapForTempled({ headline: c.cover_headline, subtitle: c.cover_subtitle })
  },
  ...c.slides.map((s, i) => ({
    slide: i + 2,
    template_id: TPL_STANDARD,
    layers: wrapForTempled({
      'slide-number': s.num,
      headline: s.headline,
      'body-text': s.body,
      'node-1': s.node1,
      'node-2': s.node2,
      'node-3': s.node3
    })
  })),
  {
    slide: 9,
    template_id: TPL_CTA,
    layers: wrapForTempled({
      'cta-headline': c.cta_headline,
      'cta-subtext': c.cta_subtext,
      'cta-badge-text': c.cta_badge
    })
  }
];

return slides.map(s => ({
  json: {
    templated_body: JSON.stringify({ template: s.template_id, format: 'png', layers: s.layers }),
    slide: s.slide,
    carousel_id: sujet.id,
    post_text: c.post_text
  }
}));

// Collecte les 9 URLs PNG générées par Templated.io
const items = $input.all();
const png_urls = items.map(i => i.json.url).filter(Boolean);

if (png_urls.length !== 9) {
  console.warn(`Attention: ${png_urls.length} slides générés au lieu de 9`);
}

const parseNode = $('Code — Parse Claude + prépare slides');
const carousel_id = parseNode.first().json.carousel_id;
const post_text = parseNode.first().json.post_text;

return [{ json: { png_urls, carousel_id, post_text } }];

// Éclate les 9 URLs en 9 items séparés pour téléchargement parallèle
const png_urls = $input.first().json.png_urls;
const carousel_id = $input.first().json.carousel_id;
const post_text = $input.first().json.post_text;

return png_urls.map((url, index) => ({
  json: { url, index, carousel_id, post_text }
}));

// Rassemble les 9 images téléchargées en un seul item avec binary
const items = $input.all();

if (items.length !== 9) {
  throw new Error(`Attendu 9 images, reçu ${items.length}`);
}

const carousel_id = items[0].json.carousel_id;
const post_text = items[0].json.post_text;
const png_urls = $('Code — Collecte PNG URLs').first().json.png_urls;

const binary = {};
items.forEach((item, i) => { binary[`image_${i}`] = item.binary.data; });

return [{ json: { carousel_id, post_text, image_count: items.length, png_urls }, binary }];
